mapper.select:
/* 전송 로그 조회 */ SELECT L.ID, L.STORE_ID, L.LOCATION_ID, L.MSG_IDX, L.BIZTALK_ID, L.RES_CODE, L.USER_ID, U.NAME AS USER_NAME, L.PHONE_NO, L.TMPL_CODE, T.TMPL_NAME, L.REQ_API_URI, L.MESSAGE_CONTENT, L.REQUEST_JSON, L.RESPONSE_JSON, L.SEND_STATUS, L.SEND_MSG_STATUS, L.SEND_DATE, L.SEND_MSG_DATE, L.CREATE_USER, L.CREATE_DATE, L.UPDATE_USER, L.UPDATE_DATE FROM biztalk_send_log L LEFT JOIN user_mst U ON L.USER_ID = U.USER_ID LEFT JOIN template_mst T ON L.TMPL_CODE = T.TMPL_CODE WHERE 1 = 1
AND L.TMPL_CODE = #{tmplCode}
AND DATE(L.SEND_DATE) >= #{startDate}
AND DATE(L.SEND_DATE) <= #{endDate}
AND U.NAME LIKE CONCAT('%', #{userName}, '%')
AND U.USER_ID LIKE CONCAT('%', #{userId}, '%')
ORDER BY L.SEND_DATE DESC

/** 알림톡 전송할 USER 리스트 */ SELECT RM.USER_ID , UM.PHONE , UM.NAME , SUM(RMD.RESERVATION_CNT) TOT_CNT FROM special_rsv_mst RM JOIN special_rsv_dtl RMD ON RM.SPECIAL_RSV_MST_ID = RMD.SPECIAL_RSV_MST_ID JOIN user_mst UM ON RM.USER_ID = UM.USER_ID JOIN special_mst SM ON RM.SPECIAL_ID = SM.SPECIAL_ID WHERE 1=1 AND RM.RESERVATION_STATUS = 'RESERVATION' AND IFNULL(RM.CANCEL_YN, 'N') = 'N' AND DATE(SM.PICKUP_END_DATE) = CURDATE() AND SM.SPECIAL_NM != '럭키드로우'
AND RM.USER_ID = #{userId}
GROUP BY RM.USER_ID, UM.PHONE, UM.NAME;

    /** 전송할 템플릿 정보 */
    SELECT * 
	FROM   template_mst
	WHERE  TMPL_CODE = #{tmplCode}
	AND    USE_YN = 'Y'
